import os
import pymysql
import json

def lambda_handler(event, context):
    # Database connection parameters
    db_host = os.environ['DB_HOST']
    db_user = os.environ['DB_USER']
    db_password = os.environ['DB_PASSWORD']
    db_name = os.environ['DB_NAME']
    
    # Validate and sanitize input
    allowed_fields = {'name', 'category', 'price_min', 'price_max'}
    search_params = {k: v for k, v in event.get('queryStringParameters', {}).items() if k in allowed_fields}
    
    # Build the query dynamically
    query = "SELECT * FROM products WHERE 1=1"
    query_params = []
    
    if 'name' in search_params:
        query += " AND name LIKE %s"
        query_params.append(f"%{search_params['name']}%")
    
    if 'category' in search_params:
        query += " AND category = %s"
        query_params.append(search_params['category'])
    
    if 'price_min' in search_params:
        query += " AND price >= %s"
        query_params.append(float(search_params['price_min']))
    
    if 'price_max' in search_params:
        query += " AND price <= %s"
        query_params.append(float(search_params['price_max']))
    
    # Connect to the database
    connection = pymysql.connect(
        host=db_host,
        user=db_user,
        password=db_password,
        database=db_name,
        cursorclass=pymysql.cursors.DictCursor
    )
    
    try:
        with connection.cursor() as cursor:
            cursor.execute(query, query_params)
            results = cursor.fetchall()
    finally:
        connection.close()
    
    # Return the results
    return {
        'statusCode': 200,
        'body': json.dumps(results),
        'headers': {
            'Content-Type': 'application/json'
        }
    }